class Solution {
public:
    int findTheLongestSubstring(string s) {
        int n = s.size();
        int res = 0;
        vector<int> count(1 << 5, -1);
        count[0] = -1;
        int mask = 0;
        for (int i = 0; i < n; i++) {
            if (s[i] == 'a') mask ^= 1;
            else if (s[i] == 'e') mask ^= 2;
            else if (s[i] == 'i') mask ^= 4;
            else if (s[i] == 'o') mask ^= 8;
            else if (s[i] == 'u') mask ^= 16;
            if (count[mask] != -1) res = max(res, i - count[mask]);
            else count[mask] = i;
        }
        return res;
    }
};
